"use client";

import { useEffect, useState } from "react";
import { apiMethods } from "@/lib/api-client";

export default function CompliancePage() {
  const [data, setData] = useState<any>(null);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const res = await apiMethods.getComplianceStatus();
        setData(res.data.data);
      } catch (err) {
        console.error("Error fetching compliance:", err);
      }
    };

    fetchData();
  }, []);

  if (!data) {
    return <div className="text-white p-10">Loading...</div>;
  }

  return (
    <div className="p-6 text-white">

      <h1 className="text-3xl font-bold mb-6">Compliance Dashboard</h1>

      {/* TOP METRICS */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">

        <div className="bg-gray-800 p-6 rounded-xl">
          <h2 className="text-lg">HIPAA Compliance</h2>
          <p className="text-3xl font-bold text-green-400">
            {data.hipaaCompliance}%
          </p>
        </div>

        <div className="bg-gray-800 p-6 rounded-xl">
          <h2 className="text-lg">DPDP Compliance</h2>
          <p className="text-3xl font-bold text-blue-400">
            {data.dpdpaCompliance}%
          </p>
        </div>

        <div className="bg-gray-800 p-6 rounded-xl">
          <h2 className="text-lg">Overall Score</h2>
          <p className="text-3xl font-bold text-purple-400">
            {data.complianceScore}%
          </p>
        </div>

      </div>

      {/* RISK SUMMARY */}
      <div className="mt-8 bg-gray-800 p-6 rounded-xl">
        <h2 className="text-xl mb-4">Risk Summary</h2>

        <div className="grid grid-cols-2 md:grid-cols-4 gap-4 text-center">
          <div>🔴 Critical: {data.risks?.critical}</div>
          <div>🟠 High: {data.risks?.high}</div>
          <div>🟡 Medium: {data.risks?.medium}</div>
          <div>🟢 Low: {data.risks?.low}</div>
        </div>
      </div>

      {/* RECOMMENDATIONS */}
      <div className="mt-8 bg-gray-800 p-6 rounded-xl">
        <h2 className="text-xl mb-4">Recommendations</h2>

        <ul className="list-disc pl-5 space-y-2">
          {data.recommendations?.map((rec: string, i: number) => (
            <li key={i}>{rec}</li>
          ))}
        </ul>
      </div>

    </div>
  );
}